import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../lib/supabaseClient';

function getRandomUsername() {
  const animals = ['Lion', 'Tiger', 'Eagle', 'Wolf', 'Falcon', 'Panther', 'Dove', 'Fox', 'Bear', 'Hawk'];
  return 'User_' + animals[Math.floor(Math.random() * animals.length)] + Math.floor(1000 + Math.random() * 9000);
}

// Helper to get local datetime string for datetime-local input
function getLocalDateTimeString() {
  const now = new Date();
  now.setSeconds(0, 0); // Remove seconds and ms for input compatibility
  const offset = now.getTimezoneOffset();
  const local = new Date(now.getTime() - offset * 60000);
  return local.toISOString().slice(0, 16);
}

// Helper to format local datetime for display
function formatLocalDateTime(dtString) {
  if (!dtString) return '';
  const dt = new Date(dtString);
  if (isNaN(dt)) return dtString;
  return dt.toLocaleString([], { year: 'numeric', month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' });
}

// Helper to generate a report ID
function generateReportId() {
  const now = new Date();
  return `#AVY-${now.getFullYear()}${String(now.getMonth()+1).padStart(2,'0')}${String(now.getDate()).padStart(2,'0')}${String(now.getHours()).padStart(2,'0')}${String(now.getMinutes()).padStart(2,'0')}${Math.floor(1000 + Math.random() * 9000)}`;
}

const initialPublic = {
  location: '',
  manualLocation: false,
  dateTime: '',
  image: null,
  description: '',
  contact: '',
  otp: '',
  otpSent: false,
  otpVerified: false,
  message: '',
  terms: false,
};
const initialAnon = {
  username: getRandomUsername(),
  dateTime: '',
  location: '',
  terms: false,
};

const ReportUnclaimedBody = () => {
  const [tab, setTab] = useState('public');
  const [publicForm, setPublicForm] = useState(initialPublic);
  const [anonForm, setAnonForm] = useState(initialAnon);
  const [publicErrors, setPublicErrors] = useState({});
  const [anonErrors, setAnonErrors] = useState({});
  const [submitting, setSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [submittedAnon, setSubmittedAnon] = useState(false);
  const [step, setStep] = useState(1);
  const [imagePreview, setImagePreview] = useState(null);
  const [reportId, setReportId] = useState(null);
  const navigate = useNavigate();

  React.useEffect(() => {
    if (!publicForm.manualLocation && navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => {
          setPublicForm((f) => ({ ...f, location: `${pos.coords.latitude}, ${pos.coords.longitude}` }));
        },
        () => {},
        { enableHighAccuracy: true }
      );
    }
    if (!publicForm.dateTime) {
      setPublicForm((f) => ({ ...f, dateTime: getLocalDateTimeString() }));
    }
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => {
          setAnonForm((f) => ({ ...f, location: `${pos.coords.latitude}, ${pos.coords.longitude}` }));
        },
        () => {},
        { enableHighAccuracy: true }
      );
    }
    if (!anonForm.dateTime) {
      setAnonForm((f) => ({ ...f, dateTime: getLocalDateTimeString() }));
    }
  }, [publicForm.manualLocation]);

  // --- Public Form Logic ---
  const validatePublic = () => {
    const e = {};
    if (!publicForm.location) e.location = 'Location is required.';
    if (!publicForm.dateTime) e.dateTime = 'Date & Time is required.';
    if (!publicForm.description?.trim()) e.description = 'Description is required.';
    if (publicForm.image && publicForm.image.size > 5 * 1024 * 1024) e.image = 'Max file size is 5MB.';
    if (publicForm.image && !['image/jpeg', 'image/png'].includes(publicForm.image.type)) e.image = 'Only JPEG/PNG allowed.';
    if (!publicForm.contact) e.contact = 'Contact is required for public report.';
    if (!publicForm.otpVerified) e.otp = 'Please verify your contact with OTP.';
    if (!publicForm.terms) e.terms = 'You must confirm the report is genuine.';
    return e;
  };
  const handlePublicChange = (e) => {
    const { name, value, type, checked, files } = e.target;
    if (type === 'checkbox') {
      setPublicForm((f) => ({ ...f, [name]: checked }));
    } else if (type === 'file') {
      setPublicForm((f) => ({ ...f, image: files[0] }));
      if (files[0]) {
        const reader = new FileReader();
        reader.onload = (ev) => setImagePreview(ev.target.result);
        reader.readAsDataURL(files[0]);
      } else {
        setImagePreview(null);
      }
    } else {
      setPublicForm((f) => ({ ...f, [name]: value }));
    }
  };
  const handleSendOtp = () => {
    setPublicForm((f) => ({ ...f, otpSent: true }));
  };
  const handleVerifyOtp = () => {
    setPublicForm((f) => ({ ...f, otpVerified: true }));
  };
  const handlePublicSubmit = async (e) => {
    e.preventDefault();
    const eObj = validatePublic();
    setPublicErrors(eObj);
    if (Object.keys(eObj).length > 0) return;
    setSubmitting(true);

    const newReportId = generateReportId();

    try {
      const { error } = await supabase
        .from('cases')
        .insert([{
          report_id: newReportId,
          report_type: 'public',
          location: publicForm.location,
          date_time: new Date(publicForm.dateTime).toISOString(),
          description: publicForm.description + (publicForm.message ? `\n\nNotes: ${publicForm.message}` : ''),
          contact: publicForm.contact,
          status: 'pending'
        }]);

      if (error) throw error;

      setSubmitted(true);
      setReportId(newReportId);
      setPublicForm(initialPublic);
      setImagePreview(null);
      setStep(1);
    } catch (err) {
      console.error('Failed to submit public report:', err);
      alert('Failed to submit report. Please try again.');
    } finally {
      setSubmitting(false);
    }
  };

  // --- Anonymous Form Logic ---
  const validateAnon = () => {
    const e = {};
    if (!anonForm.username) e.username = 'Username is required.';
    if (!anonForm.terms) e.terms = 'You must accept the terms.';
    return e;
  };
  const handleAnonChange = (e) => {
    const { name, value, type, checked } = e.target;
    if (type === 'checkbox') {
      setAnonForm((f) => ({ ...f, [name]: checked }));
    } else {
      setAnonForm((f) => ({ ...f, [name]: value }));
    }
  };
  const handleAnonSubmit = async (e) => {
    e.preventDefault();
    const eObj = validateAnon();
    setAnonErrors(eObj);
    if (Object.keys(eObj).length > 0) return;
    setSubmitting(true);

    const newReportId = generateReportId();

    try {
      const { error } = await supabase
        .from('cases')
        .insert([{
          report_id: newReportId,
          report_type: 'anonymous',
          location: anonForm.location,
          date_time: new Date(anonForm.dateTime).toISOString(),
          description: `Anonymous Report by ${anonForm.username}`,
          status: 'pending'
        }]);

      if (error) throw error;

      setSubmittedAnon(true);
      setReportId(newReportId);
      setAnonForm({ ...initialAnon, username: getRandomUsername() });
    } catch (err) {
      console.error('Failed to submit anonymous report:', err);
      alert('Failed to submit report. Please try again.');
    } finally {
      setSubmitting(false);
    }
  };

  const handleCopyReportId = () => {
    if (reportId) {
      navigator.clipboard.writeText(reportId);
    }
  };

  const inputStyle = {
    border: '1.5px solid #CBD5E0',
    borderRadius: '8px',
    padding: '0.6rem 0.85rem',
    fontSize: '0.95rem',
    color: 'var(--text-dark)',
    background: '#fff',
    width: '100%',
    transition: 'border-color 0.2s, box-shadow 0.2s',
  };

  // --- UI ---
  if (submitted || submittedAnon) {
    return (
      <div className="min-h-screen pt-16 sm:pt-20 lg:pt-24 flex flex-col items-center justify-center section-light animate-fade-in">
        <div className="inst-card w-full max-w-xl text-center animate-fade-in-up">
          <div className="flex flex-col items-center mb-6">
            <span className="block w-16 h-16 mb-2 animate-glow">
              <svg width="64" height="64" viewBox="0 0 24 24" fill="none">
                <ellipse cx="12" cy="20" rx="5" ry="2" fill="var(--amber-warn)" opacity="0.3" />
                <path className="animate-flicker" d="M12 20c3-4.5 3-9 0-13-3 4.5-3 9 0 13z" fill="var(--amber-warn)" />
                <path className="animate-flicker" d="M12 16c1.5-2.5 1.5-5 0-7.5-1.5 2.5-1.5 5 0 7.5z" fill="var(--success-green)" />
              </svg>
            </span>
            <h2 className="text-2xl font-bold mb-2" style={{ color: 'var(--navy)' }}>
              {submitted ? "Thank you for your courage and compassion." : "Thank you for reporting anonymously."}
            </h2>
            <p className="text-lg mb-2" style={{ color: 'var(--text-mid)' }}>
              {submitted 
                ? "Your report has been received with heartfelt respect and will be reviewed by our team. You've taken a step toward giving someone their identity, and their dignity." 
                : "Your anonymous report has been securely submitted and will be reviewed. You've helped bring dignity and closure."}
            </p>
            <div className="italic text-sm mb-2" style={{ color: 'var(--text-light)' }}>
              {submitted ? "“In silent departures, we find our greatest humanity.”" : "“Every voice matters, even in silence.”"}
            </div>
            {reportId && (
              <div className="flex flex-col items-center gap-2 mt-4">
                <div className="flex items-center gap-2 font-mono text-sm px-4 py-2 rounded-lg" style={{ background: 'rgba(46,125,156,0.1)', color: 'var(--navy)' }}>
                  Report ID: <span className="font-bold">{reportId}</span>
                  <button onClick={handleCopyReportId} title="Copy Report ID" className="ml-1 p-1 rounded hover:bg-white focus:outline-none focus:ring-2 focus:ring-teal">
                    <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" fill="none" viewBox="0 0 24 24"><rect x="9" y="9" width="13" height="13" rx="2" fill="var(--teal)" opacity="0.15"/><rect x="3" y="3" width="13" height="13" rx="2" stroke="var(--teal)" strokeWidth="2" fill="none"/></svg>
                  </button>
                </div>
                <span className="text-xs" style={{ color: 'var(--text-light)' }}>Tap to copy. You can use this ID to track the case {submittedAnon && "anonymously"}.</span>
              </div>
            )}
          </div>

          <button
            className="btn-primary mt-4"
            onClick={() => submitted ? navigate('/faq') : (setSubmittedAnon(false), setReportId(null))}
          >
            {submitted ? "Back to Support & Safety" : "Submit Another Anonymous Report"}
          </button>
        </div>
        <style>{`
          @keyframes flicker { 0%{opacity:1;} 50%{opacity:0.7;} 100%{opacity:1;} }
          .animate-flicker { animation: flicker 1.2s infinite alternate; }
          .animate-glow { filter: drop-shadow(0 0 12px var(--amber-warn)) drop-shadow(0 0 24px var(--amber-warn)); }
        `}</style>
      </div>
    );
  }

  return (
    <div className="min-h-screen pt-16 sm:pt-20 lg:pt-24 section-light flex flex-col">
      {/* Hero Section */}
      <section className="section-dark section-padding text-center">
        <div className="container-responsive">
          <div className="flex flex-col items-center">
            <span className="block w-16 h-16 mb-4 animate-glow">
              <svg width="64" height="64" viewBox="0 0 24 24" fill="none">
                <ellipse cx="12" cy="20" rx="7" ry="3" fill="var(--amber-warn)" opacity="0.3" />
                <path className="animate-flicker" d="M12 20c3-4.5 3-9 0-13-3 4.5-3 9 0 13z" fill="var(--amber-warn)" />
                <path className="animate-flicker" d="M12 16c1.5-2.5 1.5-5 0-7.5-1.5 2.5-1.5 5 0 7.5z" fill="var(--success-green)" />
              </svg>
            </span>
            <h1 className="text-3xl sm:text-4xl font-merriweather font-bold mb-4" style={{ color: '#fff' }}>
              “A step toward giving the forgotten a name, a voice, and the respect they deserve.”
            </h1>
            <div className="text-lg sm:text-xl font-medium mb-3" style={{ color: '#CBD5E0' }}>Your report can be anonymous, safe, and confidential.</div>
            <div className="italic text-base" style={{ color: 'rgba(255,255,255,0.6)' }}>“Every report is a step toward justice and humanity.”</div>
          </div>
        </div>
      </section>

      {/* Why this matters section */}
      <div className="w-full max-w-2xl mx-auto mt-8 mb-4 px-4">
        <div className="rounded-lg p-4 shadow-sm" style={{ background: 'rgba(245,158,11,0.1)', borderLeft: '4px solid var(--amber-warn)' }}>
          <h3 className="font-bold mb-1" style={{ color: 'var(--amber-warn)' }}>Why this matters</h3>
          <p className="text-sm sm:text-base" style={{ color: 'var(--text-dark)' }}>Every year, thousands of unclaimed and unidentified bodies are found in India. Many are never identified, and families never get closure. Your report can help bring dignity, justice, and peace to the unknown and their families.</p>
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 flex items-center justify-center pb-10">
        <div className="w-full max-w-5xl container-responsive flex flex-col md:flex-row gap-8 animate-fade-in-up">
          {/* Pill Tabs */}
          <div className="flex flex-col md:w-1/3 gap-4">
            <button 
              onClick={() => { setTab('public'); setStep(1); }} 
              className={`rounded-xl px-6 py-4 font-bold text-lg shadow-sm transition-all duration-300 ${tab==='public' ? 'text-white' : ''}`}
              style={tab === 'public' ? { background: 'var(--navy)' } : { background: 'rgba(27,58,107,0.08)', color: 'var(--navy)' }}
            >
              <span className="flex items-center gap-2">
                <span role="img" aria-label="public">🧾</span> Report Publicly
              </span>
            </button>
            <button 
              onClick={() => { setTab('anon'); setStep(1); }} 
              className={`rounded-xl px-6 py-4 font-bold text-lg shadow-sm transition-all duration-300 ${tab==='anon' ? 'text-white' : ''}`}
              style={tab === 'anon' ? { background: 'var(--teal)' } : { background: 'rgba(46,125,156,0.08)', color: 'var(--teal)' }}
            >
              <span className="flex items-center gap-2">
                <span role="img" aria-label="anon">🕵️‍♂️</span> Report Anonymously
              </span>
            </button>
          </div>

          {/* Form Section */}
          <div className="flex-1 form-card">
            <div className="mb-6 flex items-center gap-2">
              <div className="text-xs font-bold rounded-full px-3 py-1" style={{ background: 'rgba(46,125,156,0.1)', color: 'var(--teal)' }}>Step 1 of 2</div>
              <div className="flex-1 h-2 rounded-full overflow-hidden" style={{ background: '#E2E8F0' }}>
                <div className="h-2 rounded-full" style={{ width: '50%', background: 'var(--teal)' }}></div>
              </div>
            </div>

            {tab === 'public' ? (
              <form onSubmit={handlePublicSubmit} className="space-y-5">
                <div className="text-xl font-bold mb-1" style={{ color: 'var(--navy)' }}>Public Report</div>
                <div className="mb-4 text-sm" style={{ color: 'var(--text-mid)' }}>Your report will be reviewed and you will be contacted for verification.</div>

                {/* Location */}
                <div>
                  <label>📍 Location of body found *</label>
                  <div className="flex items-center gap-2 mb-2">
                    <input type="checkbox" name="manualLocation" checked={publicForm.manualLocation} onChange={handlePublicChange} id="manualLocation" />
                    <label htmlFor="manualLocation" className="text-sm mb-0 cursor-pointer" style={{ color: 'var(--text-dark)', fontWeight: 'normal' }}>Enter location manually</label>
                  </div>
                  <input
                    type="text"
                    name="location"
                    value={publicForm.location}
                    onChange={handlePublicChange}
                    style={{ ...inputStyle, background: publicForm.manualLocation ? '#fff' : '#f1f5f9', cursor: publicForm.manualLocation ? 'text' : 'not-allowed' }}
                    readOnly={!publicForm.manualLocation}
                    placeholder={publicForm.manualLocation ? "Enter location (address, landmark, etc.)" : "Fetching location..."}
                    required
                  />
                  {publicErrors.location && <p className="error-text">{publicErrors.location}</p>}
                </div>

                {/* Date & Time */}
                <div>
                  <label>📅 Date & Time of sighting *</label>
                  <input type="datetime-local" name="dateTime" value={publicForm.dateTime} onChange={handlePublicChange} style={inputStyle} required />
                  {publicErrors.dateTime && <p className="error-text">{publicErrors.dateTime}</p>}
                </div>

                {/* Image Upload */}
                <div>
                  <label>📸 Upload Image (if any)</label>
                  <input type="file" name="image" accept="image/jpeg,image/png" onChange={handlePublicChange} style={{ ...inputStyle, padding: '0.4rem' }} />
                  {imagePreview && <img src={imagePreview} alt="Preview" className="mt-2 rounded shadow w-32 h-32 object-cover" />}
                  {publicErrors.image && <p className="error-text">{publicErrors.image}</p>}
                </div>

                {/* Description */}
                <div>
                  <label>🧍 Description of the deceased *</label>
                  <textarea name="description" value={publicForm.description} onChange={handlePublicChange} style={{ ...inputStyle, minHeight: '80px' }} placeholder="Visible features, clothes, tattoos, etc." required />
                  {publicErrors.description && <p className="error-text">{publicErrors.description}</p>}
                </div>

                {/* Contact */}
                <div>
                  <label>📞 Contact number or Email *</label>
                  <input type="text" name="contact" value={publicForm.contact} onChange={handlePublicChange} style={inputStyle} placeholder="Phone or email (required)" required />

                  <div className="mt-2 flex items-center gap-2">
                    {publicForm.contact && !publicForm.otpSent && (
                      <button type="button" className="btn-secondary" style={{ padding: '0.4rem 1rem', minHeight: '32px', fontSize: '0.85rem' }} onClick={handleSendOtp}>Send OTP</button>
                    )}
                    {publicForm.otpSent && !publicForm.otpVerified && (
                      <div className="flex items-center gap-2">
                        <input type="text" name="otp" value={publicForm.otp} onChange={handlePublicChange} style={{ ...inputStyle, width: '120px' }} placeholder="OTP" />
                        <button type="button" className="btn-primary" style={{ padding: '0.4rem 1rem', minHeight: '32px', fontSize: '0.85rem' }} onClick={handleVerifyOtp}>Verify</button>
                      </div>
                    )}
                    {publicForm.otpVerified && <span className="text-sm font-bold" style={{ color: 'var(--success-green)' }}>✓ Verified</span>}
                  </div>
                  {publicErrors.contact && <p className="error-text">{publicErrors.contact}</p>}
                  {publicErrors.otp && <p className="error-text">{publicErrors.otp}</p>}
                </div>

                {/* Any other message */}
                <div>
                  <label>📄 Any other message?</label>
                  <textarea name="message" value={publicForm.message} onChange={handlePublicChange} style={{ ...inputStyle, minHeight: '60px' }} placeholder="Free form notes (optional)" />
                </div>

                {/* Terms disclaimer */}
                <div className="flex items-start gap-2 mt-4 pt-4 border-t border-gray-200">
                  <input type="checkbox" name="terms" checked={publicForm.terms} onChange={handlePublicChange} id="terms-public" required className="mt-1" />
                  <label htmlFor="terms-public" className="text-sm leading-snug cursor-pointer" style={{ color: 'var(--text-mid)', fontWeight: 'normal' }}>I confirm this report is genuine, and I understand its impact. I submit it with honesty and compassion for the unknown.</label>
                </div>
                {publicErrors.terms && <p className="error-text">{publicErrors.terms}</p>}

                <div className="text-sm font-semibold italic text-center mb-2" style={{ color: 'var(--teal)' }}>“Your courage can give closure to someone's family.”</div>

                {/* Submit Button */}
                <button type="submit" className="btn-primary w-full" disabled={submitting} style={{ borderRadius: '10px', padding: '0.9rem', fontSize: '1.05rem', opacity: submitting ? 0.6 : 1 }}>
                  {submitting ? 'Submitting...' : 'Submit Public Report'}
                </button>
              </form>
            ) : (
              <form onSubmit={handleAnonSubmit} className="space-y-5">
                <div className="text-xl font-bold mb-2 flex items-center gap-2" style={{ color: 'var(--teal)' }}>Anonymous Report</div>
                <div className="mb-3 text-sm italic flex items-center gap-2" style={{ color: 'var(--navy)' }}>
                  “Every anonymous report is a silent prayer for justice. Your courage matters.”
                </div>
                <div className="mb-4 text-sm" style={{ color: 'var(--text-mid)' }}>Your report will be stored anonymously. No personal details are collected.</div>

                {/* Username */}
                <div>
                  <label>🆔 Anonymous Username *</label>
                  <input type="text" name="username" value={anonForm.username} onChange={handleAnonChange} style={{ ...inputStyle, background: 'rgba(46,125,156,0.05)' }} required />
                  <div className="text-xs mt-1" style={{ color: 'var(--text-light)' }}>This is your auto-generated name. You remain untraceable unless you share contact details.</div>
                  {anonErrors.username && <p className="error-text">{anonErrors.username}</p>}
                </div>

                {/* Date & Time (auto) */}
                <div>
                  <label>📅 Date & Time (auto)</label>
                  <input type="text" value={formatLocalDateTime(anonForm.dateTime)} readOnly style={{ ...inputStyle, background: '#f1f5f9', cursor: 'not-allowed' }} />
                </div>

                {/* Location (auto) */}
                <div>
                  <label>📍 Location (auto)</label>
                  <input type="text" value={anonForm.location} readOnly style={{ ...inputStyle, background: '#f1f5f9', cursor: 'not-allowed' }} />
                </div>

                {/* Warning */}
                <div className="mb-2 text-sm font-semibold flex items-start gap-2 p-3 rounded-lg" style={{ background: 'rgba(192,57,43,0.08)', color: 'var(--alert-red)' }}>
                  <span>🚨</span> Submitting a false or fake report delays justice for someone in need. Please report with honesty.
                </div>

                {/* Terms */}
                <div className="flex items-start gap-2 mt-4 pt-4 border-t border-gray-200">
                  <input type="checkbox" name="terms" checked={anonForm.terms} onChange={handleAnonChange} id="terms-anon" required className="mt-1" />
                  <label htmlFor="terms-anon" className="text-sm leading-snug cursor-pointer" style={{ color: 'var(--text-mid)', fontWeight: 'normal' }}>I confirm this report is genuine, and I understand its impact. I submit it with honesty and compassion for the unknown.</label>
                </div>
                {anonErrors.terms && <p className="error-text">{anonErrors.terms}</p>}

                {/* Submit Button */}
                <button type="submit" className="w-full mt-4 py-3 rounded-xl font-bold shadow-md transition-all text-lg" style={{ background: 'var(--teal)', color: '#fff', opacity: submitting ? 0.6 : 1 }} disabled={submitting}>
                  {submitting ? 'Submitting...' : '🙌 Deliver with Compassion'}
                </button>
              </form>
            )}
          </div>
        </div>
      </div>
      <style>{`
        @keyframes flicker { 0%{opacity:1;} 50%{opacity:0.7;} 100%{opacity:1;} }
        .animate-flicker { animation: flicker 1.2s infinite alternate; }
        .animate-glow { filter: drop-shadow(0 0 12px var(--amber-warn)) drop-shadow(0 0 24px var(--amber-warn)); }
      `}</style>
    </div>
  );
};

export default ReportUnclaimedBody;
